import { ZuploContext, ZuploRequest, ZuploResponse } from "@zuplo/runtime";

export default function (options: any, policyName: string) {
  return async function (request: ZuploRequest, context: ZuploContext): Promise<ZuploRequest | ZuploResponse> {
    const authHeader = request.headers.get("Authorization");

    if (!authHeader) {
      return new Response(JSON.stringify({ error: "Unauthorized" }), {
        status: 401,
        headers: { "Content-Type": "application/json" },
      });
    }

    const parts = authHeader.split(" ");
    if (parts.length !== 2 || parts[0] !== "CustomToken") {
      return new Response(JSON.stringify({ error: "Unauthorized" }), {
        status: 401,
        headers: { "Content-Type": "application/json" },
      });
    }

    const token = parts[1];
    const runId = process.env.ZEALT_RUN_ID;
    const expectedToken = `secret-token-${runId}`;

    if (token !== expectedToken) {
      return new Response(JSON.stringify({ error: "Unauthorized" }), {
        status: 401,
        headers: { "Content-Type": "application/json" },
      });
    }

    return request;
  };
}

